#include <stdio.h>
#include <stdlib.h>

long long binomial_coefficient(int n, int k) {
    if (k > n - k) k = n - k;
    long long result = 1;
    for (int i = 0; i < k; i++) {
        result = result * (n - i) / (i + 1);
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, C, G;
        scanf("%d %d %lld", &R, &C, &G);
        int K = 0;
        long long coins_collected = 0;
        int current_column = C;
        while (coins_collected < G && current_column >= 0) {
            int max_coins = 0;
            int max_row = -1;
            for (int i = 0; i <= R && i <= current_column; i++) {
                long long coins = binomial_coefficient(i, current_column);
                if (coins > max_coins && coins <= G - coins_collected) {
                    max_coins = coins;
                    max_row = i;
                }
            }
            if (max_row == -1) break;
            coins_collected += max_coins;
            K++;
            current_column--;
        }
        printf("%d\n", K);
        current_column = C;
        coins_collected = 0;
        while (coins_collected < G && current_column >= 0) {
            int max_coins = 0;
            int max_row = -1;
            for (int i = 0; i <= R && i <= current_column; i++) {
                long long coins = binomial_coefficient(i, current_column);
                if (coins > max_coins && coins <= G - coins_collected) {
                    max_coins = coins;
                    max_row = i;
                }
            }
            if (max_row == -1) break;
            coins_collected += max_coins;
            printf("%lld ", max_coins);
            current_column--;
        }
        printf("\n");
    }
    return 0;
}

